    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKLM\SOFTWARE\Policies\Microsoft\Windows\System" -Name 'EnableSmartScreen' -ErrorAction SilentlyContinue).'EnableSmartScreen' -ne 0) { return $false }
