        reg add $k /v "PciLatencyTimerControl" /t REG_DWORD /d 32 /f | Out-Null
        reg add "HKLM\SYSTEM\CurrentControlSet\Services\nvlddmkm\Parameters" /v "DmaRemappingCompatible" /t REG_DWORD /d 0 /f | Out-Null
        foreach ($v in "LogWarningEntries","LogPagingEntries","LogEventEntries","LogErrorEntries") {
            reg add "HKLM\SYSTEM\CurrentControlSet\Services\nvlddmkm" /v $v /t REG_DWORD /d 0 /f | Out-Null
        }
    }
    Revert = {
        $k = "HKLM\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}\0000"
        foreach ($v in "D3PCLatency","F1TransitionLatency","LOWLATENCY","Node3DLowLatency","PciLatencyTimerControl","RMDeepL1EntryLatencyUsec","RmGspcMaxFtuS","RmGspcMinFtuS","RmGspcPerioduS","RMLpwrEiIdleThresholdUs","RMLpwrGrIdleThresholdUs","RMLpwrGrRgIdleThresholdUs","RMLpwrMsIdleThresholdUs","VRDirectFlipDPCDelayUs","VRDirectFlipTimingMarginUs","VRDirectJITFlipMsHybridFlipDelayUs","vrrCursorMarginUs","vrrDeflickerMarginUs","vrrDeflickerMaxUs") {
            reg delete $k /v $v /f 2>$null | Out-Null
        }
        reg delete "HKLM\SYSTEM\CurrentControlSet\Services\nvlddmkm\Parameters" /v "DmaRemappingCompatible" /f 2>$null | Out-Null
        foreach ($v in "LogWarningEntries","LogPagingEntries","LogEventEntries","LogErrorEntries") {
            reg delete "HKLM\SYSTEM\CurrentControlSet\Services\nvlddmkm" /v $v /f 2>$null | Out-Null
        }
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "AMD: Recursos de Driver (Chill/Anti-Lag/Boost/SAM)"; Category = "GPU"; Danger = $false
    Description = "Desliga Radeon Chill, Anti-Lag e Radeon Boost, e libera controles de energia/voltagem e Smart Access Memory no driver AMD."
    Apply  = {
        reg add "HKLM\SYSTEM\CurrentControlSet\Services\amdwddmg" /v "ChillEnabled" /t REG_DWORD /d 0 /f | Out-Null
        $k = "HKLM\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}\0000"
        reg add $k /v "KMD_DeLagEnabled" /t REG_DWORD /d 0 /f | Out-Null
        reg add $k /v "KMD_RadeonBoostEnabled" /t REG_DWORD /d 0 /f | Out-Null
        reg add $k /v "EnhancedSync" /t REG_DWORD /d 0 /f | Out-Null
        reg add $k /v "SAMEnabled" /t REG_DWORD /d 1 /f | Out-Null
        reg add $k /v "ForceConstantVoltage" /t REG_DWORD /d 1 /f | Out-Null
        reg add $k /v "PowerTuningUnlock" /t REG_DWORD /d 1 /f | Out-Null
        reg add $k /v "MaxPowerLimit" /t REG_DWORD /d 1 /f | Out-Null
        reg add $k /v "FanCurveOptimized" /t REG_DWORD /d 1 /f | Out-Null
        reg add $k /v "PerfStateMax" /t REG_DWORD /d 1 /f | Out-Null
        reg add $k /v "RadeonOverlayEnabled" /t REG_DWORD /d 0 /f | Out-Null
    }
    Check = {
        $k = "HKLM\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}\0000"
        try {
            if ((Get-ItemProperty -Path "Registry::HKLM\SYSTEM\CurrentControlSet\Services\amdwddmg" -Name 'ChillEnabled' -ErrorAction SilentlyContinue).'ChillEnabled' -ne 0) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'KMD_DeLagEnabled' -ErrorAction SilentlyContinue).'KMD_DeLagEnabled' -ne 0) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'KMD_RadeonBoostEnabled' -ErrorAction SilentlyContinue).'KMD_RadeonBoostEnabled' -ne 0) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'EnhancedSync' -ErrorAction SilentlyContinue).'EnhancedSync' -ne 0) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'SAMEnabled' -ErrorAction SilentlyContinue).'SAMEnabled' -ne 1) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'ForceConstantVoltage' -ErrorAction SilentlyContinue).'ForceConstantVoltage' -ne 1) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'PowerTuningUnlock' -ErrorAction SilentlyContinue).'PowerTuningUnlock' -ne 1) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'MaxPowerLimit' -ErrorAction SilentlyContinue).'MaxPowerLimit' -ne 1) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'FanCurveOptimized' -ErrorAction SilentlyContinue).'FanCurveOptimized' -ne 1) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'PerfStateMax' -ErrorAction SilentlyContinue).'PerfStateMax' -ne 1) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'RadeonOverlayEnabled' -ErrorAction SilentlyContinue).'RadeonOverlayEnabled' -ne 0) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = {
        reg delete "HKLM\SYSTEM\CurrentControlSet\Services\amdwddmg" /v "ChillEnabled" /f 2>$null | Out-Null
        $k = "HKLM\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}\0000"
        foreach ($v in "KMD_DeLagEnabled","KMD_RadeonBoostEnabled","EnhancedSync","SAMEnabled","ForceConstantVoltage","PowerTuningUnlock","MaxPowerLimit","FanCurveOptimized","PerfStateMax","RadeonOverlayEnabled") {
            reg delete $k /v $v /f 2>$null | Out-Null
        }
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Intel: Ajustes Adicionais de Overlay e Memoria (GMM)"; Category = "GPU"; Danger = $false
    Description = "Complementa os ajustes de overlay/eDP da Intel e aumenta o segmento dedicado de memoria de video (GMM)."
    Apply  = {
        Get-ChildItem "HKLM:\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}" -ErrorAction SilentlyContinue | Where-Object { (Get-ItemProperty $_.PSPath -ErrorAction SilentlyContinue).DriverDesc -match "Intel" } | ForEach-Object {
            try {
                Set-ItemProperty -Path $_.PSPath -Name "IncreaseFixedSegment" -Value 1 -ErrorAction SilentlyContinue
                Set-ItemProperty -Path $_.PSPath -Name "AdaptiveVbEnabled" -Value 0 -ErrorAction SilentlyContinue
                Set-ItemProperty -Path $_.PSPath -Name "DisablePFonDP" -Value 1 -ErrorAction SilentlyContinue
                Set-ItemProperty -Path $_.PSPath -Name "EnableCompensationForDVI" -Value 1 -ErrorAction SilentlyContinue
            } catch {}
        }
        reg add "HKLM\Software\Intel\GMM" /v "DedicatedSegmentSize" /t REG_DWORD /d 512 /f | Out-Null
    }
    Revert = {
        Get-ChildItem "HKLM:\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}" -ErrorAction SilentlyContinue | Where-Object { (Get-ItemProperty $_.PSPath -ErrorAction SilentlyContinue).DriverDesc -match "Intel" } | ForEach-Object {
            try {
                Set-ItemProperty -Path $_.PSPath -Name "IncreaseFixedSegment" -Value 0 -ErrorAction SilentlyContinue
                Set-ItemProperty -Path $_.PSPath -Name "AdaptiveVbEnabled" -Value 1 -ErrorAction SilentlyContinue
                Set-ItemProperty -Path $_.PSPath -Name "DisablePFonDP" -Value 0 -ErrorAction SilentlyContinue
                Set-ItemProperty -Path $_.PSPath -Name "EnableCompensationForDVI" -Value 0 -ErrorAction SilentlyContinue
            } catch {}
        }
        reg delete "HKLM\Software\Intel\GMM" /v "DedicatedSegmentSize" /f 2>$null | Out-Null
    }
}

# -------------------------------------------------------------------------
# MEMORIA
# -------------------------------------------------------------------------
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar SysMain (Superfetch)"; Category = "Memoria"; Danger = $false
    Description = "Desliga o pre-carregamento de apps na memoria - mais util em HD do que em SSD (servico: SysMain)."
    Apply  = { Set-ServiceStart -ServiceName "SysMain" -StartValue 4 }
    Revert = { Set-ServiceStart -ServiceName "SysMain" -StartValue 2 }
}
$Tweaks += [PSCustomObject]@{
    Name = "Habilitar Compressao de Memoria"; Category = "Memoria"; Danger = $false
    Description = "Recomendado se voce tem pouca RAM (4-12 GB) - comprime dados na memoria em vez de usar o disco."
    Apply  = { try { Enable-MMAgent -MemoryCompression -ErrorAction SilentlyContinue } catch {} }
    Revert = { try { Disable-MMAgent -MemoryCompression -ErrorAction SilentlyContinue } catch {} }
}
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar Paging Executive"; Category = "Memoria"; Danger = $false
    Description = "Mantem o sistema sempre na RAM, sem usar o disco como memoria extra - recomendado com 16GB+ de RAM."
    Apply  = { reg add "HKLM\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management" /v "DisablePagingExecutive" /t REG_DWORD /d 1 /f | Out-Null }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKLM\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management" -Name 'DisablePagingExecutive' -ErrorAction SilentlyContinue).'DisablePagingExecutive' -ne 1) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = { reg add "HKLM\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management" /v "DisablePagingExecutive" /t REG_DWORD /d 0 /f | Out-Null }
}
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar Large System Cache"; Category = "Memoria"; Danger = $false
    Description = "Prioriza a memoria RAM pros seus aplicativos em vez do cache do sistema."
    Apply  = { reg add "HKLM\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management" /v "LargeSystemCache" /t REG_DWORD /d 0 /f | Out-Null }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKLM\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management" -Name 'LargeSystemCache' -ErrorAction SilentlyContinue).'LargeSystemCache' -ne 0) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = { reg add "HKLM\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management" /v "LargeSystemCache" /t REG_DWORD /d 1 /f | Out-Null }
}
$Tweaks += [PSCustomObject]@{
    Name = "Habilitar Page Combining"; Category = "Memoria"; Danger = $false
    Description = "Junta dados identicos que estao duplicados na memoria, liberando RAM."
    Apply  = { try { Enable-MMAgent -PageCombining -ErrorAction SilentlyContinue } catch {} }
    Revert = { try { Disable-MMAgent -PageCombining -ErrorAction SilentlyContinue } catch {} }
}
$Tweaks += [PSCustomObject]@{
    Name = "Ajustar SvcHostSplitThresholdInKB"; Category = "Memoria"; Danger = $false
    Description = "Detecta a RAM instalada e ajusta o Windows pra agrupar menos processos svchost em segundo plano quanto mais RAM voce tiver."
    Apply  = {
        try {
            $ramKB = [math]::Round((Get-CimInstance Win32_ComputerSystem).TotalPhysicalMemory / 1024)
            if ($ramKB -lt 1) { $ramKB = 16777216 }
            reg add "HKLM\SYSTEM\CurrentControlSet\Control" /v "SvcHostSplitThresholdInKB" /t REG_DWORD /d $ramKB /f | Out-Null
        } catch {
            reg add "HKLM\SYSTEM\CurrentControlSet\Control" /v "SvcHostSplitThresholdInKB" /t REG_DWORD /d 16777216 /f | Out-Null
        }
    }
    Revert = { reg delete "HKLM\SYSTEM\CurrentControlSet\Control" /v "SvcHostSplitThresholdInKB" /f 2>$null | Out-Null }
}

# -------------------------------------------------------------------------
# TECLADO E MOUSE
# -------------------------------------------------------------------------
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar Aceleracao do Mouse"; Category = "InputLag"; Danger = $false
    Description = "Deixa o mouse com resposta 1:1, sem acelerar o movimento - recomendado pra jogos."
    Apply  = {
        reg add "HKCU\Control Panel\Mouse" /v "MouseSpeed" /t REG_SZ /d 0 /f | Out-Null
        reg add "HKCU\Control Panel\Mouse" /v "MouseThreshold1" /t REG_SZ /d 0 /f | Out-Null
        reg add "HKCU\Control Panel\Mouse" /v "MouseThreshold2" /t REG_SZ /d 0 /f | Out-Null
    }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKCU\Control Panel\Mouse" -Name 'MouseSpeed' -ErrorAction SilentlyContinue).'MouseSpeed' -ne '0') { return $false }
            if ((Get-ItemProperty -Path "Registry::HKCU\Control Panel\Mouse" -Name 'MouseThreshold1' -ErrorAction SilentlyContinue).'MouseThreshold1' -ne '0') { return $false }
            if ((Get-ItemProperty -Path "Registry::HKCU\Control Panel\Mouse" -Name 'MouseThreshold2' -ErrorAction SilentlyContinue).'MouseThreshold2' -ne '0') { return $false }
            return $true
        } catch { return $false }
    }
        Revert = {
        reg add "HKCU\Control Panel\Mouse" /v "MouseSpeed" /t REG_SZ /d 1 /f | Out-Null
        reg add "HKCU\Control Panel\Mouse" /v "MouseThreshold1" /t REG_SZ /d 6 /f | Out-Null
        reg add "HKCU\Control Panel\Mouse" /v "MouseThreshold2" /t REG_SZ /d 10 /f | Out-Null
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Teclado: Delay Minimo / Repeticao Maxima"; Category = "InputLag"; Danger = $false
    Description = "Deixa o teclado mais responsivo, com repeticao de tecla mais rapida."
