        reg delete "HKCU\Control Panel\Accessibility\ToggleKeys" /v "Flags" /f 2>$null | Out-Null
        reg delete "HKCU\Control Panel\Accessibility\StickyKeys" /v "Flags" /f 2>$null | Out-Null
        reg delete "HKCU\Control Panel\Accessibility\MouseKeys" /v "Flags" /f 2>$null | Out-Null
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Prioridade Alta para CSRSS (drivers de KBM)"; Category = "InputLag"; Danger = $false
    Description = "Da mais prioridade ao processo que le a entrada do teclado e mouse."
    Apply  = {
        $k = "HKLM\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options\csrss.exe\PerfOptions"
        reg add $k /v "CpuPriorityClass" /t REG_DWORD /d 4 /f | Out-Null
        reg add $k /v "IoPriority" /t REG_DWORD /d 3 /f | Out-Null
    }
    Check = {
        $k = "HKLM\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options\csrss.exe\PerfOptions"
        try {
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'CpuPriorityClass' -ErrorAction SilentlyContinue).'CpuPriorityClass' -ne 4) { return $false }
            if ((Get-ItemProperty -Path "Registry::$($k)" -Name 'IoPriority' -ErrorAction SilentlyContinue).'IoPriority' -ne 3) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = {
        $k = "HKLM\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options\csrss.exe\PerfOptions"
        reg add $k /v "CpuPriorityClass" /t REG_DWORD /d 3 /f | Out-Null
        reg add $k /v "IoPriority" /t REG_DWORD /d 2 /f | Out-Null
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Data Queue Size do Mouse/Teclado"; Category = "InputLag"; Danger = $false
    Description = "Ajusta a fila de dados do mouse e teclado - pode ajudar em dispositivos com polling rate alto."
    Apply  = {
        reg add "HKLM\SYSTEM\CurrentControlSet\Services\mouclass\Parameters" /v "MouseDataQueueSize" /t REG_DWORD /d 80 /f | Out-Null
        reg add "HKLM\SYSTEM\CurrentControlSet\Services\kbdclass\Parameters" /v "KeyboardDataQueueSize" /t REG_DWORD /d 80 /f | Out-Null
    }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKLM\SYSTEM\CurrentControlSet\Services\mouclass\Parameters" -Name 'MouseDataQueueSize' -ErrorAction SilentlyContinue).'MouseDataQueueSize' -ne 80) { return $false }
            if ((Get-ItemProperty -Path "Registry::HKLM\SYSTEM\CurrentControlSet\Services\kbdclass\Parameters" -Name 'KeyboardDataQueueSize' -ErrorAction SilentlyContinue).'KeyboardDataQueueSize' -ne 80) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = {
        reg add "HKLM\SYSTEM\CurrentControlSet\Services\mouclass\Parameters" /v "MouseDataQueueSize" /t REG_DWORD /d 100 /f | Out-Null
        reg add "HKLM\SYSTEM\CurrentControlSet\Services\kbdclass\Parameters" /v "KeyboardDataQueueSize" /t REG_DWORD /d 100 /f | Out-Null
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar Suspensao Seletiva USB"; Category = "InputLag"; Danger = $false
    Description = "Impede que as portas USB durmam sozinhas - evita mouse/teclado travando por um instante."
    Apply  = { reg add "HKLM\SYSTEM\CurrentControlSet\Services\USB" /v "DisableSelectiveSuspend" /t REG_DWORD /d 1 /f | Out-Null }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKLM\SYSTEM\CurrentControlSet\Services\USB" -Name 'DisableSelectiveSuspend' -ErrorAction SilentlyContinue).'DisableSelectiveSuspend' -ne 1) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = { reg add "HKLM\SYSTEM\CurrentControlSet\Services\USB" /v "DisableSelectiveSuspend" /t REG_DWORD /d 0 /f | Out-Null }
}
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar Economia de Energia em Dispositivos PCI/USB"; Category = "InputLag"; Danger = $false
    Description = "Desliga a suspensao seletiva e o D3Cold em todos os dispositivos PCI (inclui hubs USB de teclado/mouse), evitando microtravadas ao sair do idle."
    Apply  = {
        $devs = powershell -NoProfile -Command "Get-PnpDevice -PresentOnly | Where-Object { `$_.InstanceId -like 'PCI\VEN_*' } | ForEach-Object { `$_.InstanceId }"
        foreach ($id in $devs) {
            $regPath = "HKLM\SYSTEM\CurrentControlSet\Enum\$id\Device Parameters"
            foreach ($v in "AllowIdleIrpInD3","D3ColdSupported","DeviceSelectiveSuspended","EnableSelectiveSuspend","EnhancedPowerManagementEnabled","SelectiveSuspendEnabled","SelectiveSuspendOn") {
                reg add $regPath /v $v /t REG_DWORD /d 0 /f 2>$null | Out-Null
            }
        }
    }
    Revert = {
        $devs = powershell -NoProfile -Command "Get-PnpDevice -PresentOnly | Where-Object { `$_.InstanceId -like 'PCI\VEN_*' } | ForEach-Object { `$_.InstanceId }"
        foreach ($id in $devs) {
            $regPath = "HKLM\SYSTEM\CurrentControlSet\Enum\$id\Device Parameters"
            foreach ($v in "AllowIdleIrpInD3","D3ColdSupported","DeviceSelectiveSuspended","EnableSelectiveSuspend","EnhancedPowerManagementEnabled","SelectiveSuspendEnabled","SelectiveSuspendOn") {
                reg delete $regPath /v $v /f 2>$null | Out-Null
            }
        }
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Prioridade de Thread para Drivers USB/GPU/Rede"; Category = "InputLag"; Danger = $true
    Description = "Aumenta a prioridade de thread dos drivers USB, NVIDIA e de rede - pode reduzir input lag, mas e um ajuste nao-oficial e pode causar instabilidade em alguns PCs."
    Apply  = {
        foreach ($svc in "usbxhci","USBHUB3","nvlddmkm","NDIS") {
            reg add "HKLM\SYSTEM\CurrentControlSet\Services\$svc\Parameters" /v "ThreadPriority" /t REG_DWORD /d 31 /f | Out-Null
        }
    }
    Revert = {
        foreach ($svc in "usbxhci","USBHUB3","nvlddmkm","NDIS") {
            reg delete "HKLM\SYSTEM\CurrentControlSet\Services\$svc\Parameters" /v "ThreadPriority" /f 2>$null | Out-Null
        }
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar Gerenciamento de Energia do Mouse/Teclado (HID)"; Category = "InputLag"; Danger = $false
    Description = "Desmarca o 'Permitir que o computador desligue este dispositivo' direto nos dispositivos de mouse e teclado (nao so no controlador USB pai) - a mesma opcao do Gerenciador de Dispositivos, so que pra todos de uma vez."
    Apply  = {
        $devs = Get-PnpDevice -PresentOnly -Class Mouse,Keyboard -ErrorAction SilentlyContinue
        foreach ($d in $devs) {
            $regPath = "HKLM\SYSTEM\CurrentControlSet\Enum\$($d.InstanceId)\Device Parameters"
            foreach ($v in "AllowIdleIrpInD3","D3ColdSupported","DeviceSelectiveSuspended","EnableSelectiveSuspend","EnhancedPowerManagementEnabled","SelectiveSuspendEnabled","SelectiveSuspendOn") {
                reg add $regPath /v $v /t REG_DWORD /d 0 /f 2>$null | Out-Null
            }
        }
    }
    Revert = {
        $devs = Get-PnpDevice -PresentOnly -Class Mouse,Keyboard -ErrorAction SilentlyContinue
        foreach ($d in $devs) {
            $regPath = "HKLM\SYSTEM\CurrentControlSet\Enum\$($d.InstanceId)\Device Parameters"
            foreach ($v in "AllowIdleIrpInD3","D3ColdSupported","DeviceSelectiveSuspended","EnableSelectiveSuspend","EnhancedPowerManagementEnabled","SelectiveSuspendEnabled","SelectiveSuspendOn") {
                reg delete $regPath /v $v /f 2>$null | Out-Null
            }
        }
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar USB Selective Suspend (Plano de Energia)"; Category = "InputLag"; Danger = $false
    Description = "Desliga a opcao 'Configuracao de suspensao seletiva USB' no proprio plano de energia (nao so no registro), garantindo que a porta do mouse/teclado nunca durma."
    Apply  = {
        powercfg /setacvalueindex scheme_current 2a737441-1930-4402-8d77-b2bebba308a3 48e6b7a6-50f5-4782-a5d4-53bb8f07e226 0 | Out-Null
        powercfg /setdcvalueindex scheme_current 2a737441-1930-4402-8d77-b2bebba308a3 48e6b7a6-50f5-4782-a5d4-53bb8f07e226 0 | Out-Null
        powercfg /setactive scheme_current | Out-Null
    }
    Revert = {
        powercfg /setacvalueindex scheme_current 2a737441-1930-4402-8d77-b2bebba308a3 48e6b7a6-50f5-4782-a5d4-53bb8f07e226 1 | Out-Null
        powercfg /setdcvalueindex scheme_current 2a737441-1930-4402-8d77-b2bebba308a3 48e6b7a6-50f5-4782-a5d4-53bb8f07e226 1 | Out-Null
        powercfg /setactive scheme_current | Out-Null
    }
}
$Tweaks += [PSCustomObject]@{
    Name = "Curva de Mouse Linear 1:1 (SmoothMouseXCurve/YCurve)"; Category = "InputLag"; Danger = $false
    Description = "Remove a curva de aceleracao que o Windows aplica por baixo dos panos mesmo com o mouse em 'velocidade padrao' - complementa o tweak de Desabilitar Aceleracao do Mouse pra garantir 1 pixel movido = 1 pixel na tela."
    Apply  = {
        $xCurve = ([byte[]](0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0xa0,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x40,0x01,0x00,0x00,0x00,0x00,0x00,0x00,0x80,0x02,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x05,0x00,0x00,0x00,0x00,0x00))
        $yCurve = ([byte[]](0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x66,0xa6,0x02,0x00,0x00,0x00,0x00,0x00,0xcd,0x4c,0x05,0x00,0x00,0x00,0x00,0x00,0xa0,0x99,0x0a,0x00,0x00,0x00,0x00,0x00,0x38,0x33,0x15,0x00,0x00,0x00,0x00,0x00))
        Set-ItemProperty -Path "HKCU:\Control Panel\Mouse" -Name "SmoothMouseXCurve" -Value $xCurve -Type Binary
        Set-ItemProperty -Path "HKCU:\Control Panel\Mouse" -Name "SmoothMouseYCurve" -Value $yCurve -Type Binary
    }
    Revert = {
        Remove-ItemProperty -Path "HKCU:\Control Panel\Mouse" -Name "SmoothMouseXCurve" -ErrorAction SilentlyContinue
        Remove-ItemProperty -Path "HKCU:\Control Panel\Mouse" -Name "SmoothMouseYCurve" -ErrorAction SilentlyContinue
    }
}

# -------------------------------------------------------------------------
# ADICIONAL (limpeza + QOL + extras)
# -------------------------------------------------------------------------
$Tweaks += [PSCustomObject]@{
    Name = "Remover Dispositivos Fantasma (desconhecidos)"; Category = "Adicional"; Danger = $false
    Description = "Remove dispositivos fantasma (status Desconhecido) do gerenciador de dispositivos."
    Apply  = {
        try {
            Get-PnpDevice | Where-Object { $_.Status -eq "Unknown" } | ForEach-Object { pnputil /remove-device $_.InstanceId 2>$null | Out-Null }
            Write-Log "  [OK] Dispositivos fantasma removidos."
        }
        catch { Write-Log "  [ERRO] $($_.Exception.Message)" }
    }
    Revert = { Write-Log "  [INFO] Nao ha reversao - Windows detecta os dispositivos de novo se forem conectados." }
}
$Tweaks += [PSCustomObject]@{
    Name = "Abrir Limpeza de Disco do Windows"; Category = "Adicional"; Danger = $false
    Description = "Abre a Limpeza de Disco do Windows pra voce escolher o que apagar."
    Apply  = { Start-Process cleanmgr.exe }
    Revert = { Write-Log "  [INFO] Essa opcao so abre a ferramenta nativa do Windows - nada a reverter." }
}
$Tweaks += [PSCustomObject]@{
    Name = "Limpar Pasta Temp do Usuario e do Windows"; Category = "Adicional"; Danger = $false
    Description = "Apaga arquivos temporarios do sistema e do seu usuario."
    Apply  = {
        Get-ChildItem -Path $env:TEMP, "$env:WINDIR\Temp" -Recurse -Force -ErrorAction SilentlyContinue | Remove-Item -Force -Recurse -ErrorAction SilentlyContinue
        Write-Log "  [OK] Pastas temporarias limpas (o que estava em uso foi ignorado)."
    }
    Revert = { Write-Log "  [INFO] Limpeza de temporarios nao tem reversao." }
}
$Tweaks += [PSCustomObject]@{
    Name = "Ativar Modo Escuro"; Category = "Adicional"; Danger = $false
    Description = "Aplica o tema escuro em todo o sistema e nos aplicativos."
    Apply  = { reg add "HKCU\Software\Microsoft\Windows\CurrentVersion\Themes\Personalize" /v "AppsUseLightTheme" /t REG_DWORD /d 0 /f | Out-Null }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKCU\Software\Microsoft\Windows\CurrentVersion\Themes\Personalize" -Name 'AppsUseLightTheme' -ErrorAction SilentlyContinue).'AppsUseLightTheme' -ne 0) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = { reg add "HKCU\Software\Microsoft\Windows\CurrentVersion\Themes\Personalize" /v "AppsUseLightTheme" /t REG_DWORD /d 1 /f | Out-Null }
}
$Tweaks += [PSCustomObject]@{
    Name = "Mostrar Extensoes de Arquivo"; Category = "Adicional"; Danger = $false
    Description = "Mostra a extensao (.exe, .txt, etc) de todos os arquivos no Explorer."
    Apply  = { reg add "HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced" /v "HideFileExt" /t REG_DWORD /d 0 /f | Out-Null }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced" -Name 'HideFileExt' -ErrorAction SilentlyContinue).'HideFileExt' -ne 0) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = { reg add "HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced" /v "HideFileExt" /t REG_DWORD /d 1 /f | Out-Null }
}
$Tweaks += [PSCustomObject]@{
    Name = "Melhorar Qualidade do Papel de Parede"; Category = "Adicional"; Danger = $false
    Description = "Evita que o Windows comprima demais a qualidade do seu papel de parede."
    Apply  = { reg add "HKCU\Control Panel\Desktop" /v "JPEGImportQuality" /t REG_DWORD /d 256 /f | Out-Null }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKCU\Control Panel\Desktop" -Name 'JPEGImportQuality' -ErrorAction SilentlyContinue).'JPEGImportQuality' -ne 256) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = { reg delete "HKCU\Control Panel\Desktop" /v "JPEGImportQuality" /f 2>$null | Out-Null }
}
$Tweaks += [PSCustomObject]@{
    Name = "Desabilitar UAC"; Category = "Adicional"; Danger = $true
    Description = "⚠️ Todo programa roda como admin automaticamente. Reduz seguranca do sistema - use com cautela."
    Apply  = { reg add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System" /v "EnableLUA" /t REG_DWORD /d 0 /f | Out-Null }
    Check = {
        try {
            if ((Get-ItemProperty -Path "Registry::HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System" -Name 'EnableLUA' -ErrorAction SilentlyContinue).'EnableLUA' -ne 0) { return $false }
            return $true
        } catch { return $false }
    }
        Revert = { reg add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System" /v "EnableLUA" /t REG_DWORD /d 1 /f | Out-Null }
}
$Tweaks += [PSCustomObject]@{
    Name = "Criar Ponto de Restauracao Manual"; Category = "Adicional"; Danger = $false
    Description = "Cria um ponto de restauracao extra a qualquer momento (alem do botao no rodape)."
    Apply  = {
        try { Enable-ComputerRestore -Drive "C:\" -ErrorAction SilentlyContinue; Checkpoint-Computer -Description "LAIT TWEAKS manual" -RestorePointType "MODIFY_SETTINGS"; Write-Log "  [OK] Ponto de restauracao criado." }
        catch { Write-Log "  [ERRO] $($_.Exception.Message)" }
    }
    Revert = { Write-Log "  [INFO] Use 'rstrui.exe' pra restaurar o Windows a partir de um ponto salvo." }
}

# --------------------------------------------------------------------------
# Tweaks universais: seguros pra qualquer PC, sem downside. Aplicados
# automaticamente na tela de loading (nao aparecem no painel de selecao).
# Cada um tem Check (pra pular se ja aplicado) e Label (nome curto pra
# mostrar na tela de loading enquanto roda).
# --------------------------------------------------------------------------
$Global:UniversalTweaks = @(
    [PSCustomObject]@{
        Name = "Mostrar extensoes de arquivo"; Label = "Extensoes de arquivo"
        Apply = { reg add "HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced" /v "HideFileExt" /t REG_DWORD /d 0 /f | Out-Null }
        Check = {
            try { (Get-ItemProperty -Path "Registry::HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced" -Name 'HideFileExt' -ErrorAction Stop).'HideFileExt' -eq 0 }
            catch { $false }
        }
    }
    [PSCustomObject]@{
        Name = "Fechar apps travados mais rapido"; Label = "Apps travados + rapido"
        Apply = {
            reg add "HKCU\Control Panel\Desktop" /v "AutoEndTasks" /t REG_SZ /d "1" /f | Out-Null
            reg add "HKCU\Control Panel\Desktop" /v "HungAppTimeout" /t REG_SZ /d "1000" /f | Out-Null
            reg add "HKCU\Control Panel\Desktop" /v "WaitToKillAppTimeout" /t REG_SZ /d "2000" /f | Out-Null
        }
        Check = {
            try { (Get-ItemProperty -Path "Registry::HKCU\Control Panel\Desktop" -Name 'AutoEndTasks' -ErrorAction Stop).'AutoEndTasks' -eq "1" }
            catch { $false }
        }
    }
    [PSCustomObject]@{
        Name = "Prioridade de foreground pra apps em foco"; Label = "Prioridade apps em foco"
        Apply = { reg add "HKLM\SYSTEM\CurrentControlSet\Control\PriorityControl" /v "Win32PrioritySeparation" /t REG_DWORD /d 0x26 /f | Out-Null }
        Check = {
            try { (Get-ItemProperty -Path "Registry::HKLM\SYSTEM\CurrentControlSet\Control\PriorityControl" -Name 'Win32PrioritySeparation' -ErrorAction Stop).'Win32PrioritySeparation' -eq 38 }
            catch { $false }
        }
    }
    [PSCustomObject]@{
        Name = "Reduzir atraso do menu iniciar"; Label = "Menus mais rapidos"
        Apply = { reg add "HKCU\Control Panel\Desktop" /v "MenuShowDelay" /t REG_SZ /d "0" /f | Out-Null }
        Check = {
            try { (Get-ItemProperty -Path "Registry::HKCU\Control Panel\Desktop" -Name 'MenuShowDelay' -ErrorAction Stop).'MenuShowDelay' -eq "0" }
            catch { $false }
        }
    }
    [PSCustomObject]@{
        Name = "Habilitar TRIM/otimizacao automatica do disco"; Label = "TRIM automatico do disco"
        Apply = { fsutil behavior set DisableDeleteNotify 0 | Out-Null }
        Check = {
            try {
                $out = fsutil behavior query DisableDeleteNotify 2>$null
                return ($out -match "0")
            } catch { $false }
        }
    }
)

# ==========================================================================
# ETAPA 3: Interface Grafica (XAML + WPF)
# ==========================================================================
[xml]$xaml = @"
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="LAIT TWEAKS" Height="800" Width="1180"
        WindowStartupLocation="CenterScreen" Background="#FF0D0D10">

    <Window.Resources>
        <LinearGradientBrush x:Key="AccentGradient" StartPoint="0,0" EndPoint="1,1">
            <GradientStop Color="#FF8B5CF6" Offset="0"/>
            <GradientStop Color="#FF6366F1" Offset="1"/>
        </LinearGradientBrush>
        <SolidColorBrush x:Key="AccentBrush" Color="#FF8B5CF6"/>
        <SolidColorBrush x:Key="DangerBrush" Color="#FFEF4444"/>
        <SolidColorBrush x:Key="CardBrush" Color="#FF1B1B22"/>
        <SolidColorBrush x:Key="CardBorderBrush" Color="#FF2A2A34"/>

        <Style x:Key="NavButton" TargetType="Button">
            <Setter Property="Foreground" Value="#FFD6D6DE"/>
            <Setter Property="FontSize" Value="13.5"/>
            <Setter Property="FontWeight" Value="SemiBold"/>
            <Setter Property="Cursor" Value="Hand"/>
            <Setter Property="Height" Value="42"/>
            <Setter Property="Margin" Value="0,0,8,8"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="Button">
                        <Border x:Name="Bd" Background="#FF17151D" CornerRadius="8" BorderBrush="{StaticResource CardBorderBrush}" BorderThickness="1">
                            <Grid>
                                <Grid.ColumnDefinitions>
                                    <ColumnDefinition Width="4"/>
                                    <ColumnDefinition Width="*"/>
                                </Grid.ColumnDefinitions>
                                <Border x:Name="AccentBar" Grid.Column="0" Width="4" CornerRadius="2" Background="{StaticResource AccentBrush}" Opacity="0"/>
                                <ContentPresenter Grid.Column="1" Margin="10,0,4,0" VerticalAlignment="Center" HorizontalAlignment="Left"/>
                            </Grid>
                        </Border>
                        <ControlTemplate.Triggers>
                            <Trigger Property="Tag" Value="active">
                                <Setter TargetName="Bd" Property="Background" Value="#FF201C2B"/>
                                <Setter TargetName="AccentBar" Property="Opacity" Value="1"/>
                            </Trigger>
                            <Trigger Property="IsMouseOver" Value="True">
                                <Setter TargetName="Bd" Property="Background" Value="#FF1D1B24"/>
                            </Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <Style x:Key="TweakCheck" TargetType="CheckBox">
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="CheckBox">
                        <Border x:Name="CardBd" Background="{StaticResource CardBrush}" CornerRadius="10" Padding="14,12" Margin="0,0,0,10" BorderBrush="{StaticResource CardBorderBrush}" BorderThickness="1">
                            <Grid>
                                <Grid.ColumnDefinitions>
                                    <ColumnDefinition Width="Auto"/>
                                    <ColumnDefinition Width="*"/>
                                </Grid.ColumnDefinitions>
                                <Border x:Name="Box" Grid.Column="0" Width="20" Height="20" CornerRadius="5" BorderBrush="#FF4B4B58" BorderThickness="2" Background="Transparent" VerticalAlignment="Top" Margin="0,2,12,0">
                                    <Path x:Name="Check" Data="M2,7 L6,11 L14,2" Stroke="White" StrokeThickness="2.4" StrokeStartLineCap="Round" StrokeEndLineCap="Round" StrokeLineJoin="Round" Visibility="Collapsed"/>
                                </Border>
                                <ContentPresenter Grid.Column="1" VerticalAlignment="Center"/>
                            </Grid>
                        </Border>
                        <ControlTemplate.Triggers>
                            <Trigger Property="IsChecked" Value="True">
                                <Setter TargetName="Box" Property="Background" Value="{StaticResource AccentBrush}"/>
                                <Setter TargetName="Box" Property="BorderBrush" Value="{StaticResource AccentBrush}"/>
                                <Setter TargetName="Check" Property="Visibility" Value="Visible"/>
                                <Setter TargetName="CardBd" Property="BorderBrush" Value="{StaticResource AccentBrush}"/>
                            </Trigger>
                            <Trigger Property="IsMouseOver" Value="True">
                                <Setter TargetName="CardBd" Property="Background" Value="#FF212129"/>
                            </Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <Style x:Key="BtnPrimary" TargetType="Button">
            <Setter Property="Background" Value="{StaticResource AccentGradient}"/>
            <Setter Property="Foreground" Value="White"/>
            <Setter Property="FontWeight" Value="Bold"/>
            <Setter Property="FontSize" Value="13"/>
            <Setter Property="Cursor" Value="Hand"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="Button">
                        <Border Background="{TemplateBinding Background}" CornerRadius="8">
                            <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center" Margin="10,0"/>
                        </Border>
                        <ControlTemplate.Triggers>
                            <Trigger Property="IsMouseOver" Value="True"><Setter Property="Opacity" Value="0.88"/></Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <Style x:Key="BtnGhost" TargetType="Button">
            <Setter Property="Background" Value="#FF19191F"/>
            <Setter Property="Foreground" Value="#FFD6D6DE"/>
            <Setter Property="FontWeight" Value="SemiBold"/>
            <Setter Property="FontSize" Value="13"/>
            <Setter Property="Cursor" Value="Hand"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="Button">
                        <Border Background="{TemplateBinding Background}" CornerRadius="8" BorderBrush="{StaticResource CardBorderBrush}" BorderThickness="1">
                            <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center" Margin="10,0"/>
                        </Border>
                        <ControlTemplate.Triggers>
                            <Trigger Property="IsMouseOver" Value="True"><Setter Property="Background" Value="#FF232330"/></Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>
    </Window.Resources>

    <Grid x:Name="RootGrid">
    <DockPanel LastChildFill="True">

        <Border DockPanel.Dock="Top" Background="#FF141218" Padding="20,16">
            <Grid>
                <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="Auto"/>
                    <ColumnDefinition Width="*"/>
                    <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <Border Grid.Column="0" Width="92" Height="92" CornerRadius="18" Background="#FF000000" VerticalAlignment="Center" ClipToBounds="True">
                    <Image x:Name="LogoImage" Width="92" Height="92" Stretch="Uniform"/>
                </Border>
                <StackPanel Grid.Column="1" VerticalAlignment="Center" Margin="14,0,0,0">
                    <TextBlock Text="LAIT TWEAKS" FontSize="22" FontWeight="Bold" Foreground="White"/>
                    <TextBlock Text="Painel de Otimizacao para Windows" Foreground="#FF9A9AA5" FontSize="12" Margin="0,2,0,0"/>
                </StackPanel>
                <StackPanel Grid.Column="2" VerticalAlignment="Center" HorizontalAlignment="Right">
                    <StackPanel Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,0,0,10">
                        <Border x:Name="UserAvatarBorder" Width="30" Height="30" CornerRadius="15" Background="#FF4A4A55" ClipToBounds="True" VerticalAlignment="Center">
                            <Image x:Name="UserAvatarImage" Width="30" Height="30" Stretch="UniformToFill"/>
                        </Border>
                        <TextBlock x:Name="UserNameText" Text="" Foreground="#FFD6D6DE" FontSize="12.5" FontWeight="SemiBold" VerticalAlignment="Center" Margin="9,0,0,0"/>
                    </StackPanel>
                    <TextBlock x:Name="CounterText" Text="0 selecionados" Foreground="{StaticResource AccentBrush}" FontWeight="Bold" FontSize="13" HorizontalAlignment="Right"/>
                    <TextBlock x:Name="TotalText" Text="" Foreground="#FF7A7A85" FontSize="11" HorizontalAlignment="Right" Margin="0,2,0,0"/>
                </StackPanel>
            </Grid>
        </Border>

        <Border DockPanel.Dock="Bottom" Background="#FF141218" Padding="18,14">
            <StackPanel>
                <StackPanel Orientation="Horizontal" HorizontalAlignment="Left">
                    <Button x:Name="BtnRestore" Content="Criar Ponto de Restauracao" Style="{StaticResource BtnGhost}" Width="195" Height="36" Margin="0,0,10,0"/>
                    <Button x:Name="BtnSelectAll" Content="Marcar Todos (aba atual)" Style="{StaticResource BtnGhost}" Width="185" Height="36" Margin="0,0,10,0"/>
                    <Button x:Name="BtnClearAll" Content="Limpar Selecao" Style="{StaticResource BtnGhost}" Width="145" Height="36" Margin="0,0,10,0"/>
                    <Button x:Name="BtnRevert" Content="Reverter Selecionados" Style="{StaticResource BtnGhost}" Width="175" Height="36" Margin="0,0,10,0"/>
                    <Button x:Name="BtnApply" Content="Aplicar Selecionados" Style="{StaticResource BtnPrimary}" Width="185" Height="36"/>
                </StackPanel>
                <Border Background="#FF0A0A0C" CornerRadius="8" Margin="0,12,0,0" Padding="10">
                    <TextBox x:Name="LogBox" Height="100" Background="Transparent" Foreground="#FF8DFFA0" BorderThickness="0"
                             FontFamily="Consolas" FontSize="12" IsReadOnly="True" VerticalScrollBarVisibility="Auto" TextWrapping="Wrap"/>
                </Border>
            </StackPanel>
        </Border>

        <Grid Margin="18,12,18,0">
            <Grid.ColumnDefinitions>
                <ColumnDefinition Width="270"/>
                <ColumnDefinition Width="*"/>
            </Grid.ColumnDefinitions>

            <ScrollViewer Grid.Column="0" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" PanningMode="VerticalOnly">
                <UniformGrid x:Name="NavGrid" Columns="1" VerticalAlignment="Top"/>
            </ScrollViewer>

            <Border Grid.Column="1" Margin="16,0,0,0">
                <Grid x:Name="ContentHost"/>
            </Border>
        </Grid>

    </DockPanel>

    <Grid x:Name="LoadingOverlay" Background="#FF0D0D10">
        <Canvas x:Name="DotsCanvas" HorizontalAlignment="Center" VerticalAlignment="Center" Width="1" Height="1"/>
        <TextBlock Text="LAIT TWEAKS" Foreground="#FF6B6B78" FontSize="13" FontWeight="Bold" HorizontalAlignment="Center" VerticalAlignment="Center" Margin="0,90,0,0"/>
        <TextBlock x:Name="LoadingStatusText" Text="" Foreground="#FF9A9AA5" FontSize="12.5" HorizontalAlignment="Center" VerticalAlignment="Center" Margin="0,122,0,0" Opacity="0"/>
    </Grid>
    </Grid>
</Window>
"@

$reader = New-Object System.Xml.XmlNodeReader $xaml
$window = [Windows.Markup.XamlReader]::Load($reader)

$NavGrid      = $window.FindName("NavGrid")
$ContentHost  = $window.FindName("ContentHost")
$LoadingOverlay = $window.FindName("LoadingOverlay")
$DotsCanvas     = $window.FindName("DotsCanvas")
$BtnApply     = $window.FindName("BtnApply")
$BtnRevert    = $window.FindName("BtnRevert")
$BtnRestore   = $window.FindName("BtnRestore")
$BtnSelectAll = $window.FindName("BtnSelectAll")
$BtnClearAll  = $window.FindName("BtnClearAll")
$CounterText  = $window.FindName("CounterText")
$TotalText    = $window.FindName("TotalText")
$Global:LogBox = $window.FindName("LogBox")

$LogoImage = $window.FindName("LogoImage")
if ($LogoImage -and $Global:LogoBase64) {
    try {
        $bytes = [Convert]::FromBase64String($Global:LogoBase64)
        $ms = New-Object System.IO.MemoryStream(,$bytes)
        $bmp = New-Object System.Windows.Media.Imaging.BitmapImage
        $bmp.BeginInit()
        $bmp.CacheOption = [System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad
        $bmp.StreamSource = $ms
        $bmp.EndInit()
        $bmp.Freeze()
        $LogoImage.Source = $bmp
    } catch {
        Write-Host "Nao foi possivel carregar a logo: $($_.Exception.Message)"
    }
}

$UserAvatarImage = $window.FindName("UserAvatarImage")
$UserAvatarBorder = $window.FindName("UserAvatarBorder")
$UserNameText = $window.FindName("UserNameText")
if ($UserNameText) { $UserNameText.Text = $env:USERNAME }
if ($UserAvatarImage) {
    try {
        $avatarPath = $null
        $accPicDir = Join-Path $env:APPDATA "Microsoft\Windows\AccountPictures"
        if (Test-Path $accPicDir) {
            $candidate = Get-ChildItem -Path $accPicDir -Include "*.jpg","*.jpeg","*.png","*.bmp" -File -Recurse -ErrorAction SilentlyContinue |
                Sort-Object Length -Descending | Select-Object -First 1
            if ($candidate) { $avatarPath = $candidate.FullName }
        }
        if ($avatarPath) {
            $bmpUser = New-Object System.Windows.Media.Imaging.BitmapImage
            $bmpUser.BeginInit()
            $bmpUser.CacheOption = [System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad
            $bmpUser.UriSource = New-Object System.Uri($avatarPath)
            $bmpUser.EndInit()
            $bmpUser.Freeze()
            $UserAvatarImage.Source = $bmpUser
        }
        # Sem foto: o Border ja fica cinza (Background definido no XAML), nada a fazer.
    } catch {
        # Falhou ao carregar - mantem o circulo cinza padrao
    }
}

$categoryMeta = [ordered]@{
    "Geral"         = "🧩  Geral"
    "Debloat"       = "🧹  Debloat"
    "Armazenamento" = "💽  Armazenamento"
    "Rede"          = "🌐  Rede"
    "Energia"       = "🔋  Energia"
    "CPU"           = "🔲  CPU"
    "GPU"           = "🎨  GPU"
    "Memoria"       = "💾  Memoria"
    "TecladoMouse"  = "🖱️  Teclado e Mouse"
    "InputLag"      = "⚡  Input Lag"
    "Adicional"     = "➕  Adicional"
}

$checkboxMap   = @{}
$borderMap     = @{}
$categoryPanel = @{}
$navButtons    = @{}

function Update-Counter {
    $checked = @($checkboxMap.Keys | Where-Object { $_.IsChecked -eq $true })
    $CounterText.Text = "$($checked.Count) selecionados"
}

function Pump-UI {
    $frame = New-Object System.Windows.Threading.DispatcherFrame
    $null = $window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background, [Action]{ $frame.Continue = $false })
    [System.Windows.Threading.Dispatcher]::PushFrame($frame)
}

function Show-Category($cat) {
    foreach ($k in $categoryPanel.Keys) { $categoryPanel[$k].Visibility = "Collapsed" }
    $categoryPanel[$cat].Visibility = "Visible"
    foreach ($k in $navButtons.Keys) { $navButtons[$k].Tag = $(if ($k -eq $cat) { "active" } else { "" }) }
    $Global:CurrentCategory = $cat
}

foreach ($catKey in $categoryMeta.Keys) {
    if (-not ($Tweaks.Category -contains $catKey)) { continue }

    $scroll = New-Object System.Windows.Controls.ScrollViewer
    $panel = New-Object System.Windows.Controls.StackPanel
    $panel.Margin = "0,0,4,4"

    foreach ($t in ($Tweaks | Where-Object { $_.Category -eq $catKey })) {
        $title = New-Object System.Windows.Controls.TextBlock
        $title.Text = $t.Name
        $title.FontSize = 14
        $title.FontWeight = "SemiBold"
        $title.TextWrapping = "Wrap"
        $title.Foreground = $(if ($t.Danger) { "#FFEF4444" } else { "#FFECECF1" })

        $desc = New-Object System.Windows.Controls.TextBlock
        $desc.Text = $t.Description
        $desc.FontSize = 11.5
        $desc.Margin = "0,4,0,0"
        $desc.TextWrapping = "Wrap"
        $desc.Foreground = $(if ($t.Danger) { "#FFEF9A9A" } else { "#FF9A9AA5" })

        $stack = New-Object System.Windows.Controls.StackPanel
        $stack.Children.Add($title) | Out-Null
        $stack.Children.Add($desc) | Out-Null

        $cb = New-Object System.Windows.Controls.CheckBox
        $cb.Style = $window.Resources["TweakCheck"]
        $cb.Content = $stack
        $cb.Add_Checked({ Update-Counter })
        $cb.Add_Unchecked({ Update-Counter })

        $panel.Children.Add($cb) | Out-Null
        $checkboxMap[$cb] = $t
        $cb.ApplyTemplate() | Out-Null
        $cardBd = $cb.Template.FindName("CardBd", $cb)
        if ($cardBd) { $borderMap[$cb] = $cardBd }
    }

    $scroll.Content = $panel
    $scroll.Visibility = "Collapsed"
    $categoryPanel[$catKey] = $scroll
    $ContentHost.Children.Add($scroll) | Out-Null

    $btn = New-Object System.Windows.Controls.Button
    $btn.Style = $window.Resources["NavButton"]
    $btn.Content = $categoryMeta[$catKey]
    $btn.Tag = ""
    $capturedKey = $catKey
    $btn.Add_Click({ Show-Category $capturedKey }.GetNewClosure())
    $NavGrid.Children.Add($btn) | Out-Null
    $navButtons[$catKey] = $btn
}

