        Enable-ComputerRestore -Drive "C:\" -ErrorAction SilentlyContinue
        Checkpoint-Computer -Description "Antes do LAIT TWEAKS" -RestorePointType "MODIFY_SETTINGS"
        Write-Log "[OK] Ponto de restauracao criado."
